'use client'

import { useState } from 'react'
import { Button } from '@/components/ui/button'
import { RefreshCw, ChevronDown } from 'lucide-react'
import { useQueryClient } from '@tanstack/react-query'

interface SyncResult {
  count: number
  total: number
  message: string
}

export function SyncButton() {
  const [isLoading, setIsLoading] = useState(false)
  const [result, setResult] = useState<SyncResult | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [showMenu, setShowMenu] = useState(false)
  const queryClient = useQueryClient()

  const runSync = async (full: boolean) => {
    setIsLoading(true)
    setResult(null)
    setError(null)
    setShowMenu(false)

    try {
      const res = await fetch('/api/admin/sync', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ full }),
      })

      const data = await res.json()

      if (!res.ok) {
        setError(data.error || '동기화 실패')
      } else {
        setResult(data)
        queryClient.invalidateQueries({ queryKey: ['admin-products'] })
        queryClient.invalidateQueries({ queryKey: ['admin-stats'] })
      }
    } catch {
      setError('네트워크 오류가 발생했습니다.')
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div className="flex flex-col items-end gap-1.5">
      <div className="relative flex">
        <Button
          variant="outline"
          size="sm"
          className="gap-1.5 rounded-r-none border-r-0"
          onClick={() => runSync(false)}
          disabled={isLoading}
        >
          <RefreshCw className={`h-4 w-4 ${isLoading ? 'animate-spin' : ''}`} />
          {isLoading ? '동기화 중...' : '식약처 동기화'}
        </Button>
        <Button
          variant="outline"
          size="sm"
          className="rounded-l-none px-2"
          onClick={() => setShowMenu((v) => !v)}
          disabled={isLoading}
        >
          <ChevronDown className="h-4 w-4" />
        </Button>

        {showMenu && (
          <div className="absolute right-0 top-full z-10 mt-1 w-44 rounded-md border border-border bg-background shadow-md">
            <button
              className="w-full px-4 py-2 text-left text-sm hover:bg-muted"
              onClick={() => runSync(false)}
            >
              증분 동기화 (어제 변경분)
            </button>
            <button
              className="w-full px-4 py-2 text-left text-sm hover:bg-muted"
              onClick={() => runSync(true)}
            >
              전체 동기화 (모든 제품)
            </button>
          </div>
        )}
      </div>

      {result && (
        <p className="text-xs text-green-600 dark:text-green-400">{result.message}</p>
      )}
      {error && (
        <p className="text-xs text-destructive">{error}</p>
      )}
    </div>
  )
}
